loadstring([[local Rayfield=loadstring(game:HttpGet('https://sirius.menu/rayfield'))()local Window=Rayfield:CreateWindow({Name="Zayden's Monkey Mod Menu",LoadingTitle="Zayden's Monkey Mod Menu",LoadingSubtitle="Triston's a femboy 💅 | bomb tag survival go crazy",ConfigurationSaving={Enabled=true,FolderName="ZaydenMonkey",FileName="Config"}})local p=game:GetService("Players")local u=game:GetService("UserInputService")local r=game:GetService("RunService")local lp=p.LocalPlayer local s=16 local j=50 local ij=false local f=false local n=false local fs=50 local fbv=nil local fc=nil local nc=nil local he=false local hs=10 local oh={}local ba={}local hc=nil local at=false local ac=nil local lt={}u.JumpRequest:Connect(function()if ij and lp.Character and lp.Character:FindFirstChildOfClass("Humanoid")then lp.Character:FindFirstChildOfClass("Humanoid"):ChangeState(Enum.HumanoidStateType.Jumping)end end)local function am()local c=lp.Character if not c then return end local h=c:FindFirstChildOfClass("Humanoid")if h then h.WalkSpeed=s h.JumpPower=j end end lp.CharacterAdded:Connect(function()task.wait(0.5)am()end)local function uoh()for _,pl in ipairs(p:GetPlayers())do if pl~=lp and pl.Character then local ch=pl.Character local rt=ch:FindFirstChild("HumanoidRootPart")if rt then if not oh[pl.Name]then oh[pl.Name]=rt.Size end rt.Size=Vector3.new(hs,hs,hs)if not ba[pl.Name]then local ad=Instance.new("BoxHandleAdornment")ad.Name="MHV"ad.Adornee=rt ad.Size=Vector3.new(hs,hs,hs)ad.Color3=Color3.fromRGB(100,100,100)ad.Transparency=0.5 ad.AlwaysOnTop=true ad.ZIndex=1 ad.Parent=rt ba[pl.Name]=ad else ba[pl.Name].Size=Vector3.new(hs,hs,hs)end end end end end local function eh()if hc then return end hc=r.Heartbeat:Connect(uoh)uoh()end local function dh()if hc then hc:Disconnect()hc=nil end for n,s in pairs(oh)do local pl=p:FindFirstChild(n)if pl and pl.Character then local rt=pl.Character:FindFirstChild("HumanoidRootPart")if rt then rt.Size=s end end end for _,ad in pairs(ba)do if ad and ad.Parent then ad:Destroy()end end ba={}oh={}end local function sat()if ac then return end ac=r.Heartbeat:Connect(function()if not at then return end local c=lp.Character if not c or not c:FindFirstChild("HumanoidRootPart")then return end local rt=c.HumanoidRootPart local hb=false local bp=c:FindFirstChild("Bomb")or(c:FindFirstChild("Head")and c.Head:FindFirstChild("Bomb"))if bp then hb=true end if not hb then return end local t=tick()for _,pl in ipairs(p:GetPlayers())do if pl~=lp and pl.Character then local tc=pl.Character local tr=tc:FindFirstChild("HumanoidRootPart")if tr then local d=(rt.Position-tr.Position).Magnitude if d<(hs+8)then if not lt[pl]or t-lt[pl]>0.35 then local tp=bp or rt firetouchinterest(tp,tr,0)firetouchinterest(tp,tr,1)lt[pl]=t end end end end end end)end local function stopat()if ac then ac:Disconnect()ac=nil end lt={}end local function sf()if f then return end f=true local c=lp.Character if not c or not c:FindFirstChild("HumanoidRootPart")then f=false return end local
